  addRule(rule: ValidatorRule): void {
    this.rules.push(rule);
  }

  /**
   * Get all configured rules
   */
  getRules(): ValidatorRule[] {
    return [...this.rules];
  }

  /**
   * Check if command is allowed (convenience method)
   */
  isAllowed(command: string): boolean {
